// ── SEPARATE RESULTS BY TYPE ──
let atoPageHtml = '';
let benchmarkArticles = [], rentArticles = [], startupArticles = [];

for (const item of all) {
  const j = item.json;
  // ATO page fetch returns body as string or object
  if (typeof j === 'string' && j.includes('small-business-benchmarks')) {
    atoPageHtml = j;
  } else if (j?.body && typeof j.body === 'string') {
    atoPageHtml = j.body;
  } else if (j?.organic_results && Array.isArray(j.organic_results)) {
    // Distinguish 3 serp calls by result count or content
    if (!benchmarkArticles.length) benchmarkArticles = j.organic_results;
    else if (!rentArticles.length) rentArticles = j.organic_results;
    else startupArticles = j.organic_results;
  }
}

const formatArticles = (arr, max) => arr.slice(0, max).map((r, i) =>
