// ── MATCH BUSINESS TYPE ──
const btLower = (inputs.business_type || '').toLowerCase();
const catLower = (inputs.industry_category || '').toLowerCase();
let matchedKey = null;
for (const key of Object.keys(ATO_BENCHMARKS)) {
  if (btLower.includes(key) || catLower.includes(key)) { matchedKey = key; break; }
}
if (!matchedKey) {
  if (/food|beverage|hospitality|catering/i.test(catLower)) matchedKey = 'cafe';
  else matchedKey = 'retail';
}
const bench = ATO_BENCHMARKS[matchedKey];

// ── TRY TO EXTRACT ATO RATIOS FROM SCRAPED PAGE ──
// If ATO page was successfully fetched, look for percentage patterns near the category
let atoLiveData = null;
if (atoPageHtml && atoPageHtml.length > 500) {
  // Look for cost of sales % and gross profit % patterns
  const cosMatch = atoPageHtml.match(/cost of sales[\s\S]{0,200}?(\d{1,2})\s*(?:to|–|-)\s*(\d{1,2})\s*%/i);
  const gpMatch  = atoPageHtml.match(/gross profit[\s\S]{0,200}?(\d{1,2})\s*(?:to|–|-)\s*(\d{1,2})\s*%/i);
  if (cosMatch || gpMatch) {
    atoLiveData = {
      fetched: true,
      cos_range: cosMatch ? `${cosMatch[1]}-${cosMatch[2]}%` : bench.cost_of_sales_pct_range + '%',
      gp_range:  gpMatch  ? `${gpMatch[1]}-${gpMatch[2]}%`   : bench.gross_margin_pct_range + '%'
    };
  }
}

// ── CITY TIER ──
const tier1 = ['sydney','melbourne','brisbane','perth','adelaide'];
const tier2 = ['gold coast','newcastle','wollongong','canberra','geelong','hobart','darwin','townsville','cairns'];
const cityLower = (inputs.city || '').toLowerCase();
const cityTier = tier1.some(c => cityLower.includes(c)) ? 'Tier 1'
               : tier2.some(c => cityLower.includes(c)) ? 'Tier 2' : 'Tier 3';

// ── REVENUE BASELINE ──
// Use A5 revenue if passed through, otherwise estimate
const a5Revenue = parseFloat(inputs.a5_monthly_revenue) || 0;
const avgTicket = parseFloat(inputs.avg_ticket_max) || parseFloat(inputs.avg_ticket_min) || 0;
const estimatedMonthlyRev = a5Revenue > 0 ? a5Revenue : avgTicket * 40 * 26;
const revenueSource = a5Revenue > 0 ? 'A5 agent output' : '40 customers/day × avg ticket × 26 days (estimate)';

// ── RENT BURDEN ──
const monthlyRent = parseFloat(inputs.monthly_rent_budget_max) || 0;
const rentBurdenPct = estimatedMonthlyRev > 0
  ? parseFloat(((monthlyRent / estimatedMonthlyRev) * 100).toFixed(1)) : null;
const rentBurdenLabel = !rentBurdenPct ? 'Unknown'
  : rentBurdenPct <= 8  ? 'Excellent'
  : rentBurdenPct <= 12 ? 'Healthy'
  : rentBurdenPct <= 15 ? 'Caution'
  : rentBurdenPct <= 20 ? 'High Risk' : 'Avoid';
const rentBurdenScore = !rentBurdenPct ? 50
  : rentBurdenPct <= 8  ? 95
  : rentBurdenPct <= 12 ? 80
  : rentBurdenPct <= 15 ? 60
  : rentBurdenPct <= 20 ? 35 : 10;
const benchmarkMaxRent = estimatedMonthlyRev > 0
  ? `$${Math.round(estimatedMonthlyRev * bench.rent_pct_max / 100).toLocaleString()}/mo` : 'N/A';

// ── CAPITALISATION ──
const setupBudget = parseFloat(inputs.setup_budget) || 0;
const fitoutRange = bench.fitout_range || [60000, 200000];
const capitalisationAssessment = setupBudget < fitoutRange[0] ? 'Under-capitalised'
  : setupBudget > fitoutRange[1] * 1.3   ? 'Over-capitalised'
  : setupBudget <= fitoutRange[1]        ? 'Well-capitalised' : 'Adequate';

// ── 3-YEAR PROJECTION ──
const annualRevY1 = estimatedMonthlyRev > 0 ? Math.round(estimatedMonthlyRev * 12 * 0.75) : null;
const annualRevY2 = estimatedMonthlyRev > 0 ? Math.round(estimatedMonthlyRev * 12 * 0.90) : null;
const annualRevY3 = estimatedMonthlyRev > 0 ? Math.round(estimatedMonthlyRev * 12 * 1.05) : null;

// ── PERFORMANCE PERCENTILE ──
const performancePercentile = !rentBurdenPct ? 50
  : rentBurdenPct <= bench.rent_pct_max * 0.5  ? 85
  : rentBurdenPct <= bench.rent_pct_max * 0.75 ? 70
  : rentBurdenPct <= bench.rent_pct_max        ? 55
  : rentBurdenPct <= bench.rent_pct_max * 1.25 ? 35 : 15;

return [{ json: {
