  industry_category:  inputs.industry_category,
  city: inputs.city, area: inputs.area, locality: inputs.locality,
  country: inputs.country, currency: inputs.currency,
  avg_ticket_min: inputs.avg_ticket_min, avg_ticket_max: inputs.avg_ticket_max,
  monthly_rent_budget_max: inputs.monthly_rent_budget_max,
  setup_budget: inputs.setup_budget, email: inputs.email,
  // ATO data
  matched_category:   matchedKey,
  ato_anzsic_code:    bench.anzsic,
  ato_source:         bench.source,
  ato_live_fetched:   atoLiveData?.fetched || false,
  ato_live_data:      atoLiveData,
  bench,
  city_tier:          cityTier,
  // Revenue
  revenue_source:          revenueSource,
  estimated_monthly_rev:   estimatedMonthlyRev,
  a5_revenue_used:         a5Revenue > 0,
  // Rent burden
  rent_burden_pct:    rentBurdenPct,
  rent_burden_label:  rentBurdenLabel,
  rent_burden_score:  rentBurdenScore,
  benchmark_max_rent: benchmarkMaxRent,
  // Other computed
  capitalisation:          capitalisationAssessment,
  fitout_range_min:        fitoutRange[0],
  fitout_range_max:        fitoutRange[1],
  performance_percentile:  performancePercentile,
  annual_rev_y1: annualRevY1, annual_rev_y2: annualRevY2, annual_rev_y3: annualRevY3,
  // Articles
  benchmark_text:    formatArticles(benchmarkArticles, 5) || 'No benchmark articles found.',
  rent_burden_text:  formatArticles(rentArticles, 4)     || 'No rent burden articles found.',
  startup_cost_text: formatArticles(startupArticles, 4)  || 'No startup cost articles found.',
  data_sources: {
    ato_page_fetched:    atoLiveData?.fetched || false,
    ato_benchmark_table: bench.source,
    anzsic_code:         bench.anzsic,
    benchmark_articles:  benchmarkArticles.length,
    rent_articles:       rentArticles.length,
    startup_articles:    startupArticles.length,
    revenue_basis:       revenueSource
  }
}}];

const inputJson = $input.first().json;
const rawText = inputJson.output || inputJson.text || JSON.stringify(inputJson);

let analysis;
try {
  let cleaned = rawText.trim()
    .replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```\s*$/i,'').trim();
  const s = cleaned.indexOf('{'), e = cleaned.lastIndexOf('}');
  if (s !== -1 && e > s) cleaned = cleaned.slice(s, e+1);
  cleaned = cleaned.replace(/(:\s*)(\d{1,3}(?:,\d{3})+)([,\}\]\s\n])/g,(m,pre,num,post)=>pre+num.replace(/,/g,'')+post);
  analysis = JSON.parse(cleaned);
} catch(e) {
  analysis = { parse_error: true, raw_response: rawText.slice(0,800) };
}

const d = $('Compute Benchmarks & Rent Burden').first().json;

return [{ json: {
  agent_id:   'A7',
  agent_name: 'Industry Benchmarks (ATO-verified Australian)',
  status:     analysis.parse_error ? 'error' : 'success',
  timestamp:  new Date().toISOString(),
  email:      d.email,
  inputs_used: {
    business_type:     d.business_type,
    industry_category: d.industry_category,
    location:          `${d.area}, ${d.city}`,
    city_tier:         d.city_tier,
    monthly_rent:      d.monthly_rent_budget_max,
    setup_budget:      d.setup_budget,
    avg_ticket:        `$${d.avg_ticket_min}–$${d.avg_ticket_max}`
  },
  data_sources: {
    primary:             d.ato_source,
    anzsic_code:         d.ato_anzsic_code,
    ato_live_fetched:    d.ato_live_fetched,
    serp_research:       d.data_sources,
    revenue_basis:       d.revenue_source,
    ai_synthesis:        'GPT-4o'
  },
  computed: {
    matched_category:       d.matched_category,
    city_tier:              d.city_tier,
    rent_burden_pct:        d.rent_burden_pct,
    rent_burden_label:      d.rent_burden_label,
    rent_burden_score:      d.rent_burden_score,
    benchmark_max_rent:     d.benchmark_max_rent,
    capitalisation:         d.capitalisation,
    performance_percentile: d.performance_percentile,
    annual_rev_y1:          d.annual_rev_y1,
    annual_rev_y2:          d.annual_rev_y2,
    annual_rev_y3:          d.annual_rev_y3,
    a5_revenue_used:        d.a5_revenue_used
  },
  outputs: {
    benchmark_score:          analysis.benchmark_score          ?? null,
    benchmark_verdict:        analysis.benchmark_verdict         || null,
    data_credibility:         analysis.data_credibility         || 'ATO-verified',
    ato_citation:             analysis.ato_citation             || d.ato_source,
    category_matched:         analysis.category_matched          || d.matched_category,
    city_tier:                analysis.city_tier                 || d.city_tier,
    rent_burden:              analysis.rent_burden               || { pct: d.rent_burden_pct, label: d.rent_burden_label, score: d.rent_burden_score, benchmark_max_affordable_rent: d.benchmark_max_rent },
    break_even_benchmark:     analysis.break_even_benchmark      || null,
    revenue_benchmark:        analysis.revenue_benchmark         || null,
    gross_margin_benchmark:   analysis.gross_margin_benchmark    || null,
    three_year_projection:    analysis.three_year_projection     || { year1_revenue: d.annual_rev_y1 ? `$${d.annual_rev_y1.toLocaleString()}` : null, year2_revenue: d.annual_rev_y2 ? `$${d.annual_rev_y2.toLocaleString()}` : null, year3_revenue: d.annual_rev_y3 ? `$${d.annual_rev_y3.toLocaleString()}` : null },
    capitalisation_assessment: analysis.capitalisation_assessment || { assessment: d.capitalisation },
    industry_context:         analysis.industry_context          || null,
    performance_percentile:   analysis.performance_percentile   ?? d.performance_percentile,
    key_risks:                analysis.key_risks                 || [],
    benchmark_recommendations: analysis.benchmark_recommendations || [],
    overall_benchmark_verdict: analysis.overall_benchmark_verdict || null,
    agent_notes:              analysis.agent_notes               || null
  }
}}];


// ── Output validation ──
